import numpy as np
from scipy import stats

def one_sample_t(sample, mu0):
    return stats.ttest_1samp(sample, mu0)

def two_sample_t(a, b, equal_var=False):
    # Welch's t by default (equal_var=False) handles unequal variances.
    return stats.ttest_ind(a, b, equal_var=equal_var)

def paired_t(a, b):
    return stats.ttest_rel(a, b)
